#include<bits/stdc++.h>
using namespace std;
int a[8005];
int main()
{
	int n,q;
	cin>>n>>q;
	for(int i=1;i<=n;i++)cin>>a[i];
	while(q--){
		int b;
		cin>>b;
		if(b==1){
			int x,v;;
			cin>>x>>v;
			a[x]=v;
//			for(int i=1;i<=n;i++)cout<<a[i]<<" ";
//			cout<<endl;
		}else{
			int x;
			cin>>x;
			int cnt=0,cnt2=0;
			for(int i=1;i<x;i++){
				if(a[i]>a[x])cnt++;
			}
//			cout<<cnt<<endl;
			for(int i=x+1;i<=n;i++){
				if(a[i]<a[x])cnt2++;
			}
//			cout<<cnt2<<endl;
			cout<<x-cnt+cnt2<<endl;
		}
	}
}
